    async function loadMachines() { try { machinePage = 1; const scope = document.getElementById('bindEmail').value.trim(); const emailScope = document.getElementById('machineEmailSearch').value.trim(); const showAll = document.getElementById('machinesShowAll')?.checked; let path = '/api/admin/debug/machines'; if (emailScope) { path = `/api/admin/debug/machines?email=${encodeURIComponent(emailScope)}`; } else if (scope) { const user = await lookupScopedUser(scope); if (!user || !user.id) throw new Error(tr('noHubUser', { email: scope })); path = `/api/admin/debug/machines?user_id=${encodeURIComponent(user.id)}`; } else if (showAll) { path = '/api/admin/debug/machines?all=1'; } const data = await api(path); renderMachineList(data.machines || []); } catch (err) { setOutput(tr('machinesLoadFailed', { error: err.message })); } }
