    async function loadInvitationCodeStatus() { try { const data = await api('/api/admin/invitation-codes/status'); invitationCodeRequired = !!data.invitation_code_required; renderInvitationCodeToggle(); } catch (err) { const msg = inv('statusLoadFailed', { error: err.message }); setOutput(msg); } }
    async function toggleInvitationCodeRequired() { try { const newVal = !invitationCodeRequired; const data = await api('/api/admin/invitation-codes/toggle', { method: 'POST', body: JSON.stringify({ required: newVal }) }); invitationCodeRequired = !!data.invitation_code_required; renderInvitationCodeToggle(); const msg = inv('toggleSuccess'); setOutput(msg); showToast(msg, 'success'); } catch (err) { const msg = inv('toggleFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    function renderInvitationCodeToggle() { const badge = document.getElementById('invCodeToggleBadge'); const btn = document.getElementById('invCodeToggleBtn'); if (badge) { badge.textContent = invitationCodeRequired ? inv('toggleEnabled') : inv('toggleDisabled'); badge.className = 'badge ' + (invitationCodeRequired ? 'ok' : 'warn'); } if (btn) { btn.textContent = invitationCodeRequired ? inv('toggleDisabled') : inv('toggleEnabled'); btn.className = invitationCodeRequired ? 'btn-danger' : 'btn-primary'; } }
    async function generateInvitationCodes() { try { const countInput = document.getElementById('invCodeCount'); const count = parseInt(countInput.value, 10) || 5; const data = await api('/api/admin/invitation-codes/generate', { method: 'POST', body: JSON.stringify({ count }) }); const msg = inv('generateSuccess', { count: String((data.codes || []).length) }); setOutput(msg); showToast(msg, 'success'); await loadInvitationCodes(); } catch (err) { const msg = inv('generateFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function loadInvitationCodes() { try { let path = '/api/admin/invitation-codes'; const params = []; if (invitationStatusFilter) params.push('status=' + encodeURIComponent(invitationStatusFilter)); if (invitationSearchTerm) params.push('search=' + encodeURIComponent(invitationSearchTerm)); params.push('page=' + invitationPage); params.push('page_size=' + invitationPageSize); if (params.length) path += '?' + params.join('&'); const data = await api(path); invitationCodesCache = data.codes || []; invitationCodesTotal = data.total || 0; renderInvitationCodeList(); } catch (err) { const msg = inv('loadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    let invitationSearchTimer = null;
    function onInvitationSearch() { clearTimeout(invitationSearchTimer); invitationSearchTimer = setTimeout(() => { invitationSearchTerm = (document.getElementById('invCodeSearch')?.value || '').trim(); invitationPage = 1; loadInvitationCodes(); }, 300); }
    function onInvitationFilterChange() { invitationStatusFilter = document.getElementById('invCodeFilter')?.value || ''; invitationPage = 1; loadInvitationCodes(); }
    function renderInvitationCodeList() { const root = document.getElementById('invitationCodeList'); const pager = document.getElementById('invitationCodesPager'); const pagerMeta = document.getElementById('invitationCodesPagerMeta'); const prevBtn = document.getElementById('invitationCodesPrevButton'); const nextBtn = document.getElementById('invitationCodesNextButton'); if (!root) return; if (!invitationCodesCache.length) { root.innerHTML = '<div class="hint">' + inv('emptyList') + '</div>'; if (pager) pager.classList.add('hidden'); return; } root.innerHTML = '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px">' + invitationCodesCache.map(c => { const isUsed = c.status === 'used'; const badgeClass = isUsed ? 'warn' : 'ok'; const statusText = isUsed ? inv('statusUsed') : inv('statusUnused'); const usedInfo = isUsed ? `<div class="item-meta" style="font-size:11px">${inv('usedBy')}: ${c.used_by_email || '-'}</div>` : ''; return `<div style="border:1px solid var(--border);border-radius:8px;padding:10px;${isUsed ? 'opacity:.6' : ''}"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-family:Consolas,monospace;font-size:13px;letter-spacing:.05em;font-weight:600">${c.code}</span><span class="badge ${badgeClass}" style="font-size:11px">${statusText}</span></div>${usedInfo}<div class="item-meta" style="font-size:11px">${inv('createdAt')}: ${c.created_at || '-'}</div></div>`; }).join('') + '</div>'; if (pager) { const totalPages = Math.max(1, Math.ceil(invitationCodesTotal / invitationPageSize)); const start = (invitationPage - 1) * invitationPageSize + 1; const end = start + invitationCodesCache.length - 1; if (pagerMeta) pagerMeta.textContent = invitationCodesTotal > invitationPageSize ? inv('pageSummary', { start: String(start), end: String(end), total: String(invitationCodesTotal) }) : inv('pageSingle', { total: String(invitationCodesTotal) }); if (prevBtn) prevBtn.disabled = invitationPage <= 1; if (nextBtn) nextBtn.disabled = invitationPage >= totalPages; pager.classList.toggle('hidden', invitationCodesTotal <= invitationPageSize); } }
    function changeInvitationPage(step) { const totalPages = Math.max(1, Math.ceil(invitationCodesTotal / invitationPageSize)); invitationPage = Math.min(totalPages, Math.max(1, invitationPage + step)); loadInvitationCodes(); }
    function exportInvitationCodes() { const params = []; if (invitationStatusFilter) params.push('status=' + encodeURIComponent(invitationStatusFilter)); if (invitationSearchTerm) params.push('search=' + encodeURIComponent(invitationSearchTerm)); let url = '/api/admin/invitation-codes/export'; if (params.length) url += '?' + params.join('&'); const a = document.createElement('a'); a.href = url; a.download = 'invitation-codes.txt'; const headers = {}; if (token()) headers['Authorization'] = 'Bearer ' + token(); fetch(url, { headers }).then(r => r.blob()).then(blob => { const blobUrl = URL.createObjectURL(blob); a.href = blobUrl; a.click(); URL.revokeObjectURL(blobUrl); }).catch(err => { const msg = inv('loadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); }); }
    async function loadPwaEnrollments() { try { const data = await api('/api/admin/enrollments/all'); pwaEnrollmentsCache = data.enrollments || []; renderPwaEnrollments(); } catch (err) { const msg = pwa('loadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    function renderPwaEnrollments() { const root = document.getElementById('pwaEnrollmentList'); if (!root) return; if (!pwaEnrollmentsCache.length) { root.innerHTML = '<div class="hint">' + pwa('emptyList') + '</div>'; return; } root.innerHTML = pwaEnrollmentsCache.map(e => { const isPending = e.status === 'pending'; const badgeClass = isPending ? 'warn' : e.status === 'approved' ? 'ok' : 'danger'; const statusLabel = isPending ? pwa('statusPending') : e.status === 'approved' ? pwa('statusApproved') : pwa('statusRejected'); const actions = isPending ? `<div style="display:flex;gap:8px"><button class="btn-primary" style="height:34px;font-size:13px;padding:0 14px" onclick="approvePwaEnrollment('${e.id}','${e.email.replace(/'/g, "\\'")}')">${pwa('approve')}</button><button class="btn-danger" style="height:34px;font-size:13px;padding:0 14px" onclick="rejectPwaEnrollment('${e.id}','${e.email.replace(/'/g, "\\'")}')">${pwa('reject')}</button></div>` : ''; return `<div class="item" style="margin-bottom:12px"><div class="item-head"><div><div class="item-title">${e.email}</div><div class="item-meta">${pwa('note')}: ${e.note || '-'}</div><div class="item-meta">${pwa('createdAt')}: ${e.created_at || '-'}</div></div><div style="display:flex;gap:8px;align-items:center"><span class="badge ${badgeClass}">${statusLabel}</span>${actions}</div></div></div>`; }).join(''); }
    async function approvePwaEnrollment(id, email) { if (!confirm(pwa('approveConfirm', { email }))) return; try { const data = await api('/api/admin/enrollments/approve', { method: 'POST', body: JSON.stringify({ id }) }); const msg = pwa('approveSuccess', { email, sn: data.user?.sn || '-' }); setOutput(msg); showToast(msg, 'success'); await loadPwaEnrollments(); } catch (err) { const msg = pwa('approveFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function rejectPwaEnrollment(id, email) { if (!confirm(pwa('rejectConfirm', { email }))) return; try { await api('/api/admin/enrollments/reject', { method: 'POST', body: JSON.stringify({ id }) }); const msg = pwa('rejectSuccess'); setOutput(msg); showToast(msg, 'success'); await loadPwaEnrollments(); } catch (err) { const msg = pwa('rejectFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function manualApprovePwaEmail() { const email = document.getElementById('pwaManualEmail').value.trim(); if (!email) return; try { const data = await api('/api/admin/users/manual-bind', { method: 'POST', body: JSON.stringify({ email }) }); const msg = pwa('manualApproveSuccess', { email, sn: data.user?.sn || '-' }); setOutput(msg); showToast(msg, 'success'); document.getElementById('pwaManualEmail').value = ''; await loadPwaEnrollments(); } catch (err) { const msg = pwa('manualApproveFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function loadFeishuConfig() { try { const data = await api('/api/admin/feishu/config'); document.getElementById('feishuEnabled').checked = !!data.enabled; document.getElementById('feishuAppId').value = data.app_id || ''; document.getElementById('feishuAppSecret').value = data.app_secret || ''; loadFeishuBindings(); } catch (err) { const msg = fsh('loadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function saveFeishuConfig() { try { const payload = { enabled: document.getElementById('feishuEnabled').checked, app_id: document.getElementById('feishuAppId').value.trim(), app_secret: document.getElementById('feishuAppSecret').value }; const data = await api('/api/admin/feishu/config', { method: 'POST', body: JSON.stringify(payload) }); document.getElementById('feishuEnabled').checked = !!data.enabled; document.getElementById('feishuAppId').value = data.app_id || ''; document.getElementById('feishuAppSecret').value = data.app_secret || ''; const msg = fsh('saved'); setOutput(msg); showToast(msg, 'success'); } catch (err) { const msg = fsh('saveFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function loadFeishuBindings() { try { const data = await api('/api/admin/feishu/bindings'); const bindings = data.bindings || []; const root = document.getElementById('feishuBindingsList'); if (!root) return; if (!bindings.length) { root.innerHTML = '<div class="hint">' + fsh('noBindings') + '</div>'; return; } root.innerHTML = bindings.map(b => `<div class="item" style="margin-bottom:8px"><div class="item-head"><div><div class="item-title">${b.email}</div><div class="item-meta mono">${b.open_id}</div></div><button class="btn-danger" style="height:32px;font-size:12px;padding:0 10px" onclick="unbindFeishu('${b.email.replace(/'/g, "\\'")}')">${fsh('unbind')}</button></div></div>`).join(''); } catch (err) { const msg = fsh('bindingsLoadFailed', { error: err.message }); setOutput(msg); } }
    async function unbindFeishu(email) { if (!confirm(fsh('unbindConfirm', { email }))) return; try { await api('/api/admin/feishu/bindings?email=' + encodeURIComponent(email), { method: 'DELETE' }); const msg = fsh('unbindSuccess'); setOutput(msg); showToast(msg, 'success'); loadFeishuBindings(); } catch (err) { const msg = fsh('unbindFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function loadOpenclawImConfig() { try { const data = await api('/api/admin/settings/openclaw_im'); document.getElementById('openclawImEnabled').checked = !!data.enabled; document.getElementById('openclawImWebhookUrl').value = data.webhook_url || 'http://127.0.0.1:3210/outbound'; document.getElementById('openclawImSecret').value = data.secret || ''; } catch (err) { const msg = ocim('loadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function saveOpenclawImConfig() { try { const payload = { enabled: document.getElementById('openclawImEnabled').checked, webhook_url: document.getElementById('openclawImWebhookUrl').value.trim(), secret: document.getElementById('openclawImSecret').value }; const data = await api('/api/admin/settings/openclaw_im', { method: 'POST', body: JSON.stringify(payload) }); document.getElementById('openclawImEnabled').checked = !!data.enabled; document.getElementById('openclawImWebhookUrl').value = data.webhook_url || ''; document.getElementById('openclawImSecret').value = data.secret || ''; const msg = ocim('saved'); setOutput(msg); showToast(msg, 'success'); } catch (err) { const msg = ocim('saveFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function testOpenclawImWebhook() { const btn = document.getElementById('openclawImTestBtn'); if (btn) { btn.disabled = true; btn.textContent = ocim('testing'); } try { await saveOpenclawImConfig(); const data = await api('/api/admin/settings/openclaw_im/test', { method: 'POST' }); if (data.ok) { const msg = ocim('testSuccess', { status: String(data.status) }); setOutput(msg); showToast(msg, 'success'); } else { const msg = ocim('testFailed', { message: data.message || 'Unknown error' }); setOutput(msg); showToast(msg, 'error'); } } catch (err) { const msg = ocim('testFailed', { message: err.message }); setOutput(msg); showToast(msg, 'error'); } finally { if (btn) { btn.disabled = false; btn.textContent = ocim('testWebhook'); } } }
    async function loadQQBotConfig() { try { const data = await api('/api/admin/settings/qqbot'); document.getElementById('qqbotEnabled').checked = !!data.enabled; document.getElementById('qqbotAppId').value = data.app_id || ''; document.getElementById('qqbotAppSecret').value = data.app_secret || ''; loadQQBotBindings(); } catch (err) { const msg = qqb('loadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
