    async function loadQQBotBindings() { try { const data = await api('/api/admin/qqbot/bindings'); const bindings = data.bindings || []; const root = document.getElementById('qqbotBindingsList'); if (!root) return; if (!bindings.length) { root.innerHTML = '<div class="hint">' + qqb('noBindings') + '</div>'; return; } root.innerHTML = bindings.map(b => `<div class="item" style="margin-bottom:8px"><div class="item-head"><div><div class="item-title">${b.email}</div><div class="item-meta mono">${b.open_id}</div></div><button class="btn-danger" style="height:32px;font-size:12px;padding:0 10px" onclick="unbindQQBot('${b.open_id.replace(/'/g, "\\'")}')">${qqb('unbind')}</button></div></div>`).join(''); } catch (err) { const msg = qqb('bindingsLoadFailed', { error: err.message }); setOutput(msg); } }
    async function unbindQQBot(openId) { if (!confirm(qqb('unbindConfirm', { email: openId }))) return; try { await api('/api/admin/qqbot/bindings?open_id=' + encodeURIComponent(openId), { method: 'DELETE' }); const msg = qqb('unbindSuccess'); setOutput(msg); showToast(msg, 'success'); loadQQBotBindings(); } catch (err) { const msg = qqb('unbindFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function refreshAll() { await Promise.all([loadCenterStatus(), loadBlockedEmails(), loadInvites(), loadBoundUsers(), loadMailConfig(), loadFeishuConfig(), loadMachines(), loadPwaEnrollments()]); }
    applyI18n(); if (token()) { setAuthState(true); restoreTab(); refreshAll(); } else { setAuthState(false); refreshAuthStage(); }
  